/** @deprecated since 5.0, use the [Popup](https://developers.arcgis.com/javascript/latest/references/map-components/components/arcgis-popup) and [Editor](https://developers.arcgis.com/javascript/latest/references/map-components/components/arcgis-editor) component to view and edit attachments instead. */
export type AttachmentsDisplay = "auto" | "preview" | "list";

/**
 * @deprecated since 5.0, use the [Popup](https://developers.arcgis.com/javascript/latest/references/map-components/components/arcgis-popup) and [Editor](https://developers.arcgis.com/javascript/latest/references/map-components/components/arcgis-editor) component to view and edit attachments instead.
 * @since 5.0
 */
export interface Operations {
  /**
   * Indicates whether to allow adding attachments. Default value is `true`.
   *
   * @since 5.0
   */
  add?: boolean;
  /**
   * Indicates whether to allow updating an existing attachment. Default value is `true`.
   *
   * @since 5.0
   */
  update?: boolean;
  /**
   * Indicates whether to allow deleting an existing attachment. Default value is `true`.
   *
   * @since 5.0
   */
  delete?: boolean;
}

/**
 * An object that specifies the available attachments capabilities.
 *
 * @deprecated since 5.0, use the [Popup](https://developers.arcgis.com/javascript/latest/map-components/arcgis-popup) and [Editor](https://developers.arcgis.com/javascript/latest/map-components/arcgis-editor) component to view and edit attachments instead.
 * @since 5.0
 */
export interface AttachmentsCapabilities {
  /**
   * Indicates whether to allow attachment editing. The feature layer must be enabled to support editing. Default value is `false`.
   *
   * @since 5.0
   */
  editing?: boolean;
  /**
   * Describes the configurable attachments operations. See the object specification below.
   *
   * @since 5.0
   */
  operations?: Operations;
}